<?phpclass AdminShippingAjax {    static function zoneSave($ci, $model) {        $result['status'] = 'error';        $result['message'] = 'Lưu dữ liệu thất bại';        if(Request::post()) {            $post = Request::post();            $zone_id = (int)Request::post('zone_id');            if( $zone_id == 0 ) {                if($post['zone_name'] != '' && have_posts( $post['zone_locations'] ) || $post['zone_type'] != '') {                    $data['zone_name'] = Str::clear($post['zone_name']);                    $data['zone_type'] = Str::clear($post['zone_type']);                    $id = ShippingZones::insert(['zone_name' => $data['zone_name'],'zone_type' => $data['zone_type']]);                    if( $id != 0 ) {                        $zone['zone_id'] 		= $id;                        $zone['location_code']	= 'VN';                        $states = Cart_Location::cities();                        foreach ($post['zone_locations'] as $value) {                            $value = Str::clear($value);                            if( isset($states[$value])) {                                $zone['location_type']	= $value;                                ShippingZonesLocation::insert($zone);                            }                        }                        $zones = ShippingZones::gets();                        ob_start();                        foreach ($zones as $value): ?>                            <tr class="js_shipping_zone__item">                                <td>                                    <?php echo $value->zone_name;?>                                </td>                                <td>                                    <?php foreach ($value->locations as $location): ?>                                        <?php echo $states[$location->location_type];?>                                    <?php endforeach ?>                                </td>                                <td>                                    <?php echo ShippingZones::type($value->zone_type);?>                                </td>                                <td class="sort">                                    <button class="js_shipping_zone__btn_delete btn-red btn-icon" type="button" data-id="<?php echo $value->id;?>">Xóa</button>                                    <a href="<?php echo Url::admin(sicommerce_cart::url('setting').'&tab=shipping&section='.SHIP_KEY.'&zone_id='.$value->id);?>" class="btn-edit btn-blue btn-icon">Edit</a>                                </td>                            </tr>                        <?php endforeach;                        $result['data'] = ob_get_contents();                        ob_end_clean();                        $result['status'] 	= 'success';                        $result['message'] 	= 'Lưu dữ liệu thành công';                    }                }            }            else {                $zone = ShippingZones::get( $zone_id );                if(have_posts($zone)) {                    if(isset($post['zone_name'])) $data['zone_name'] 	= Str::clear($post['zone_name']);                    if(isset($post['zone_type'])) $data['zone_type'] 	= Str::clear($post['zone_type']);                    if(isset($post['zone_price'])) $data['zone_price'] = (int)Str::clear($post['zone_price']);                    $data['id'] = $zone_id;                    if(ShippingZones::insert($data)) {                        $locations = $post['zone_locations'];                        foreach ($zone->locations as $location) {                            if(in_array( $location->location_type, $locations ) === false ) {                                $model->settable('shipping_zones_locations')->delete(Qr::set('zone_id', $zone_id)->where('location_type', $location->location_type));                            } else unset($locations[array_search( $location->location_type, $locations) ]);                        }                        if(have_posts($locations)) {                            $zone_location['zone_id'] 		= $zone_id;                            $zone_location['location_code']	= 'VN';                            foreach ($locations as $value) {                                $zone_location['location_type']	= $value;                                ShippingZonesLocation::insert($zone_location);                            }                        }                        $result['status'] 	= 'success';                        $result['message'] 	= 'Lưu dữ liệu thành công';                    }                }            }        }        echo json_encode( $result );    }    static function zoneDelete( $ci, $model ) {        $result['status'] = 'error';        $result['message'] = 'Xóa dữ liệu thất bại';        if( Request::post() ) {            $zone_id = (int)Request::post('zone_id');            if(have_posts(ShippingZones::delete($zone_id))) {                $result['status'] 	= 'success';                $result['message'] 	= 'Xóa dữ liệu thành công';            }        }        echo json_encode( $result );    }    static function districtsSave($ci, $model) {        $result['status'] = 'error';        $result['message'] = 'Lưu dữ liệu thất bại';        if(Request::post()) {            $post = Request::post();            if($post['districts_price'] != '' && have_posts( $post['districts_locations'] ) || $post['zone_id'] != '') {                $shipping = Option::get('cart_shipping');                if (!empty($shipping[SHIP_KEY]['range_price']) && $shipping[SHIP_KEY]['range_price'] == 'range_price'){                    $data['districts_price_min'] 	= Str::clear( $post['districts_price_min'] );                    $data['districts_price_max'] 	= Str::clear( $post['districts_price_max'] );                }                $data['zone_id'] 			= (int)Str::clear( $post['zone_id'] );                $data['districts_price'] 	= Str::clear( $post['districts_price'] );                if(!isset($post['districts_id']) || $post['districts_id'] == 0) {                    $id = ShippingDistricts::insert($data);                    if(!empty($id)) {                        $districts_locations['districts_id'] 		= $id;                        $districts = Cart_Location::districts();                        foreach ($post['districts_locations'] as $value) {                            $value = explode('_', Str::clear($value) );                            $districts_locations['location_type']	= $value[0];                            $districts_locations['location_code']	= $value[1];                            if(isset($districts[$districts_locations['location_type']][$districts_locations['location_code']])) {                                ShippingDistrictsLocation::insert($districts_locations);                            }                        }                        $zone_districts = ShippingDistricts::get(Qr::set($id));                        $zone_districts->locations = ShippingDistrictsLocation::gets(Qr::set('districts_id', $id));                        ob_start(); ?>                        <tr class="js_shipping_districts__item">                            <td>                                <?php                                $zone = ShippingZones::get( $data['zone_id'] );                                $locations = array();                                foreach ($zone->locations as $value) {                                    $locations[$value->location_type] = $value;                                }                                $states 	= Cart_Location::cities();                                $districts 	= Cart_Location::districts();                                $districts_option = array();                                foreach ($locations as $key =>$location):                                    foreach ($districts[$key] as $key_districts => $name_districts):                                        $districts_option[$key.'_'.$key_districts] = $name_districts;                                    endforeach;                                endforeach;                                $districts_locations = array();                                foreach ($zone_districts->locations as $location) {                                    $districts_locations[$location->location_type.'_'.$location->location_code] = $location;                                }                                ?>                                <select class="form-control zone_locations-multiple" name="zone_districts[<?php echo $zone_districts->id;?>][locations]" multiple>                                    <?php foreach ($districts_option as $key_districts => $name_districts): ?>                                        <option value="<?php echo $key_districts;?>" <?php echo ( isset($districts_locations[$key_districts]) )?'selected=selected':'';?>><?php echo $name_districts;?></option>                                    <?php endforeach ?>                                </select>                            </td>                            <?php if (!empty($shipping[SHIP_KEY]['range_price']) && $shipping[SHIP_KEY]['range_price'] == 'range_price'){ ?>                                <td>                                    <input type="number" class="form-control" value="<?php echo $zone_districts->districts_price_min;?>" name="zone_districts[<?php echo $zone_districts->id;?>][min]">                                </td>                                <td>                                    <input type="number" class="form-control" value="<?php echo $zone_districts->districts_price_max;?>" name="zone_districts[<?php echo $zone_districts->id;?>][max]">                                </td>                            <?php } ?>                            <td>                                <input type="number" class="form-control" value="<?php echo $zone_districts->districts_price;?>" name="zone_districts[<?php echo $zone_districts->id;?>][price]">                            </td>                            <td class="sort">                                <button class="js_zone_districts__delete btn-red btn-icon" data-id="<?php echo $zone_districts->id;?>">Xóa</button>                                <button class="js_zone_districts__edit btn-blue btn-icon" data-id="<?php echo $zone_districts->id;?>">Lưu</button>                            </td>                        </tr>                        <?php                        $result['data'] = ob_get_contents();                        ob_end_clean();                        $result['status'] 	= 'success';                        $result['message'] 	= 'Lưu dữ liệu thành công';                    }                }                else {                    $id = (int)$post['districts_id'];                    $data['districts_price'] 	= Str::clear( $post['districts_price']);                    $data['id'] 	            = $id;                    ShippingDistricts::insert($data);                    $model->settable('shipping_districts_locations')->delete(Qr::set('districts_id', $id));                    $districts = Cart_Location::districts();                    $districts_locations['districts_id'] 		= $id;                    foreach ($post['districts_locations'] as $value) {                        $value = explode('_', Str::clear($value) );                        $districts_locations['location_type']	= $value[0];                        $districts_locations['location_code']	= $value[1];                        if(isset($districts[$districts_locations['location_type']][$districts_locations['location_code']])) {                            ShippingDistrictsLocation::insert($districts_locations);                        }                    }                    $result['status'] 	= 'success';                    $result['message'] 	= 'Lưu dữ liệu thành công';                }            }        }        echo json_encode( $result );    }    static function districtsDelete( $ci, $model ) {        $result['status'] = 'error';        $result['message'] = 'Xóa dữ liệu thất bại';        if( Request::post() ) {            $post = Request::post();            $id = (int)$post['districts_id'];            $model->settable('shipping_districts');            if($model->delete(Qr::set($id))) {                $model->settable('shipping_districts_locations')->delete_where(Qr::set('districts_id', $id));                $result['status'] 	= 'success';                $result['message'] 	= 'Xóa dữ liệu thành công';            }        }        echo json_encode( $result );    }}Ajax::admin('AdminShippingAjax::zoneSave');Ajax::admin('AdminShippingAjax::zoneDelete');Ajax::admin('AdminShippingAjax::districtsSave');Ajax::admin('AdminShippingAjax::districtsDelete');